#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        long long *f = (long long*)malloc((N+1)*sizeof(long long));
        for(int i=0;i<=N;i++) scanf("%lld",&f[i]);
        long long S = f[0];
        long long A=0,B=0,C=0;
        for(int k=0;(1<<k)<=N;k++){
            int idx = 1<<k;
            long long delta = (f[idx]-S)/idx; // guaranteed integer
            long long cnt = (3 - delta)/2; // 0..3
            if(cnt>=1){ A |= 1LL<<k; cnt--; }
            if(cnt>=1){ B |= 1LL<<k; cnt--; }
            if(cnt>=1){ C |= 1LL<<k; cnt--; }
        }
        printf("%lld %lld %lld\n",A,B,C);
        free(f);
    }
    return 0;
}

