import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        StringBuilder sb = new StringBuilder();
        while (T-- > 0) {
            int N = fs.nextInt();
            long[] f = new long[N+1];
            for (int i = 0; i <= N; i++) f[i] = fs.nextLong();
            long S = f[0];
            long A = 0, B = 0, C = 0;
            for (int k = 0; (1 << k) <= N; k++) {
                int idx = 1 << k;
                long delta = (f[idx] - S) / idx; // integer
                long cnt = (3 - delta) / 2; // 0..3
                if (cnt > 0) { A |= 1L << k; cnt--; }
                if (cnt > 0) { B |= 1L << k; cnt--; }
                if (cnt > 0) { C |= 1L << k; cnt--; }
            }
            sb.append(A).append(' ').append(B).append(' ').append(C).append('\n');
        }
        System.out.print(sb.toString());
    }
    // fast scanner
    static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in){ this.in = in; }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        long nextLong() throws IOException {
            int c; do { c = readByte(); } while (c <= ' ');
            boolean neg = false;
            if (c == '-') { neg = true; c = readByte(); }
            long val = 0;
            while (c > ' ') {
                val = val * 10 + (c - '0');
                c = readByte();
            }
            return neg ? -val : val;
        }
        int nextInt() throws IOException { return (int) nextLong(); }
    }
}

